import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for the bug fix: Starting a line with || causes internal error from ktlint --format
 * See: https://github.com/pinterest/ktlint/issues/...
 */
internal class IndentationRuleOrOperatorTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a line starting with OR operator should not throw NPE`() {
        val code =
            """
            package com.my.lint.rules

            import com.pinterest.ktlint.rule.engine.core.api.Rule
            import com.pinterest.ktlint.rule.engine.core.api.RuleId
            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule : Rule(
                RuleId("my-ruleset:my-rule-id"),
                Rule.About(maintainer = "Me", repositoryUrl = "repositoryUrl", issueTrackerUrl = "issueTrackerUrl")
            ) {

                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {

                    if (node.text.contains("this")
                        || node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()
        // The test should not throw an exception. If it completes without error, the fix is working.
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a line starting with OR operator in if condition should not throw NPE`() {
        val code =
            """
            fun test() {
                if (foo
                    || bar
                ) {
                    println("test")
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a line starting with OR operator in return statement should not throw NPE`() {
        val code =
            """
            fun test(): Boolean {
                return foo
                    || bar
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a line starting with OR operator in value assignment should not throw NPE`() {
        val code =
            """
            val result = condition1
                || condition2
                || condition3
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

